import{_ as d,o as a,c as i,ag as r}from"./chunks/framework.DXGyWiRo.js";const e="/images/lekt1001.jpg",n="/images/lekt1003.jpg",s="/images/lekt1002.jpg",u="/images/lekt1004.jpg",k=JSON.parse('{"title":"Lektion 10","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion10.md","filePath":"lektionen/lektion10.md"}'),l={name:"lektionen/lektion10.md"};function p(h,t,o,m,b,g){return a(),i("div",null,[...t[0]||(t[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-10" tabindex="-1">Lektion 10 <a class="header-anchor" href="#lektion-10" aria-label="Permalink to &quot;Lektion 10&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>10.1. Der Passivsatz</li><li>10.2. Der Instrumentalis = tṛtīyā f. = तृतीया = &quot;dritte Kasusendung&quot; <ul><li>10.2.1. Zum Gebrauch des Instrumentalis (tṛtīyā = तृतीया)</li></ul></li><li>10.3. Das sogenannte Cerebralisationsgesetz für -n- (ein Wortsandhi)</li><li>10.4. Das Passiv, Indikativ Präsens (yak = यक्) <ul><li>10.4.1. Sonderregeln zur Bildung des Passiv</li></ul></li><li>10.5. Wortliste</li><li>10.6. Übung</li><li>10.7. Wortliste 2</li><li>10.8. Lese- und Übersetzungsübung</li></ul><h2 id="_10-1-der-passivsatz" tabindex="-1">10.1. Der Passivsatz <a class="header-anchor" href="#_10-1-der-passivsatz" aria-label="Permalink to &quot;10.1. Der Passivsatz&quot;">​</a></h2><p>| Schema: (Agens - kartṛ - im Instrumentalis (tṛtīyā) - (direktes Objekt - karman - im Nominativ) - passive Verbalform</p><p>z.B.</p><p>brāhmaṇena deva ijyate = ब्राह्मणेन देव इज्यते =  &quot;Ein Brahmane verehrt einen Gott mit einem Opfer&quot; (wörtlich: &quot;Ein Gott wird von einem Brahmanen mit einem Opfer verehrt.&quot;)</p><p>Dieser Satz ist völlig (!) bedeutungsgleich mit dem Satz:</p><p>brāhmanō devaṃ yajati / yajate ) ब्राह्मणो देवं यजति / यजते</p><p>| | --- | | Im Passivsatz steht der Agens (kartṛ) im Instrumentalis (tṛtīyā f. &quot;dritte Kasusendung&quot;), das direkte Objekt (karmnan n.) im Nominativ (prathamā f.).</p><p>Passivsätze, in denen der Agens nicht bezeichnet wird, haben meist unpersönliche Bedeutung (&quot;man&quot;):</p><p>z.B.</p><p>ijyate = इज्यते &quot;Man Opfert&quot; (wörtlich: &quot;es wird mit einem Opfer verehrt&quot;)</p><p>| | Auch wenn der entsprechende aktive Satz einen Akkusativ (dvitīyā) des Zieles enthalten würde, kann dieser im Passivsatz in den Nominativ (prathamā) gesetzt werden:</p><p>Dem Aktivsatz rāmo grāmaṃ gacchati = रामो ग्रामं गच्छति = &quot;Rāma geht ins Dorf.&quot; entsprechen die Passivsätze:</p><p>rāmeṇa grāmaṃ gamyate = रामेण ग्रामं गम्यते bzw. alternativ rāmeṇa grāmo gamyate = रामेण ग्रामो गम्यते</p><p>| | Intransitive Verben (Verben ohne direktes Objekt) haben häufig Passivkonstruktionen, bes. auch in höflichen Aufforderungen:</p><p>z.B.</p><p>praviśyatām = प्रविश्यताम् = &quot;Man möge eintreten = Bitte treten Sie ein = Herein!&quot;<br> niṣadyatām = निषद्यताम् = &quot;Man möge sich setzen = Bitte setzen Sie sich = Bitte nehmen Sie Platz&quot;</p><p>|</p><p>Sanskritkonstruktionen sind im Sanskrit - besonders im gesprochenen Sanskrit - ausgesprochen häufig: das Passiv ist ja auch leichter bildbar als z.B. zahlreiche Präsensstämme.</p><p><img src="'+e+'" alt=""></p><p>Sanskrit-Passivsätze dürfen im Allgemeinen im Deutschen nicht durch einen Passivsatz wiedergegeben werden, da das deutsche Passiv eine ganz andere stilistische Funktion hat.</p><p><img src="'+e+'" alt=""></p><h2 id="_10-2-der-instrumentalis-trtiya-f-तृतीया-dritte-kasusendung" tabindex="-1">10.2. Der Instrumentalis = tṛtīyā f. = तृतीया = &quot;dritte Kasusendung&quot; <a class="header-anchor" href="#_10-2-der-instrumentalis-trtiya-f-तृतीया-dritte-kasusendung" aria-label="Permalink to &quot;10.2. Der Instrumentalis = tṛtīyā f. = तृतीया = &quot;dritte Kasusendung&quot;&quot;">​</a></h2><p>Die regulären Endungen des Instrumentalis (tṛtīyā):</p><ul><li>Singular: -ā</li><li>Plural: -bhis</li></ul><p>Regelmäßige Bildungen:</p><table tabindex="0"><thead><tr><th></th><th>Instrumentalis singular</th><th>Instrumentalis plural</th></tr></thead><tbody><tr><td>Feminina auf -i: śruti</td><td></td><td></td></tr><tr><td>श्रुति</td><td>śruty-ā</td><td></td></tr><tr><td>श्रुत्या</td><td>śruti-bhis</td><td></td></tr><tr><td>श्रितिभिस्</td><td></td><td></td></tr><tr><td>Feminina auf -ī: devī</td><td></td><td></td></tr><tr><td>देवी</td><td>devy-ā</td><td></td></tr><tr><td>देव्या</td><td>devī-bhis</td><td></td></tr><tr><td>देवीभिस्</td><td></td><td></td></tr><tr><td>Feminina auf -u: dhenu</td><td></td><td></td></tr><tr><td>धेनु</td><td>dhenv-ā</td><td></td></tr><tr><td>धेन्वा</td><td>dhenu-bhis</td><td></td></tr><tr><td>धेनुभिस्</td><td></td><td></td></tr></tbody></table><p>Maskulina auf -u und -u sowie Feminina auf -ā bilden den Instrumentalis singular unregelmäßig:</p><table tabindex="0"><thead><tr><th></th><th>Instrumentalis singular</th><th>Instrumentalis plural</th></tr></thead><tbody><tr><td>Maskulina auf -i: kavi</td><td></td><td></td></tr><tr><td>कवि</td><td>kavi-n-ā</td><td></td></tr><tr><td>कविना</td><td>kavi-bhis</td><td></td></tr><tr><td>कविभिस्</td><td></td><td></td></tr><tr><td>Maskulina auf -u: paśu</td><td></td><td></td></tr><tr><td>पशु</td><td>paśu-n-ā</td><td></td></tr><tr><td>पशु्ना</td><td>paśu-bhis</td><td></td></tr><tr><td>पशुभिस्</td><td></td><td></td></tr><tr><td>Feminina auf -ā: devatā</td><td></td><td></td></tr><tr><td>देवता</td><td>devat-ay-ā</td><td></td></tr><tr><td>देवतया</td><td>devatā-bhis</td><td></td></tr><tr><td>देव्ताभिस्</td><td></td><td></td></tr></tbody></table><p>Maskulina und Neutra auf -a bilden den Instrumentalis im Singular und Plural unregelmäßig:</p><table tabindex="0"><thead><tr><th></th><th>Instrumentalis singular</th><th>Instrumentalis plural</th></tr></thead><tbody><tr><td>Maskulina auf -a: deva</td><td></td><td></td></tr><tr><td>देव</td><td>devena</td><td></td></tr><tr><td>देवेन</td><td>devais</td><td></td></tr><tr><td>देवैस्</td><td></td><td></td></tr><tr><td>Neutra auf -a: phala</td><td></td><td></td></tr><tr><td>फल</td><td>phalena</td><td></td></tr><tr><td>फलेन</td><td>phalais</td><td></td></tr><tr><td>फलैस्</td><td></td><td></td></tr></tbody></table><p>Fragepronomen kim:</p><table tabindex="0"><thead><tr><th></th><th>Instrumentalis singular</th><th>Instrumentalis plural</th></tr></thead><tbody><tr><td>Maskulinum / Neutrum</td><td>kena</td><td></td></tr><tr><td>केन</td><td>kais</td><td></td></tr><tr><td>कैस्</td><td></td><td></td></tr><tr><td>Femininum</td><td>kayā</td><td></td></tr><tr><td>कया</td><td>kābhis</td><td></td></tr><tr><td>काभिस्</td><td></td><td></td></tr></tbody></table><p>Demonstrativpronomina:</p><table tabindex="0"><thead><tr><th></th><th></th><th>Instrumentalis singular</th><th>Instrumentalis plural</th></tr></thead><tbody><tr><td>tad</td><td></td><td></td><td></td></tr><tr><td>&quot;er, sie, es; der, die, das&quot; (Erwähnte)</td><td></td><td></td><td></td></tr><tr><td>तद्</td><td>Maskulinum / Neutrum</td><td>tena</td><td></td></tr><tr><td>तेन</td><td>tais</td><td></td><td></td></tr><tr><td>तैस्</td><td></td><td></td><td></td></tr><tr><td></td><td>Femininum</td><td>tayā</td><td></td></tr><tr><td>तया</td><td>tābhis</td><td></td><td></td></tr><tr><td>ताभिस्</td><td></td><td></td><td></td></tr><tr><td>etad</td><td></td><td></td><td></td></tr><tr><td>&quot;dieser, diese, dieses&quot; (dem Sprechenden sehr Nahe)</td><td></td><td></td><td></td></tr><tr><td>एतद्</td><td>Maskulinum / Neutrum</td><td>etena / enena</td><td></td></tr><tr><td>एतेन / एनेन</td><td>etais</td><td></td><td></td></tr><tr><td>एतैस्</td><td></td><td></td><td></td></tr><tr><td></td><td>Femininum</td><td>etāya / enāya</td><td></td></tr><tr><td>एताय /  एनाय</td><td>etābhis</td><td></td><td></td></tr><tr><td>एताभिस्</td><td></td><td></td><td></td></tr><tr><td>idam</td><td></td><td></td><td></td></tr><tr><td>&quot;dieser, diese, dieses&quot; (Nahe)</td><td></td><td></td><td></td></tr><tr><td>इदम्</td><td>Maskulinum / Neutrum</td><td>anena /enena</td><td></td></tr><tr><td>अनेन / एनेन</td><td>ebhis</td><td></td><td></td></tr><tr><td>एभिस्</td><td></td><td></td><td></td></tr><tr><td></td><td>Femininum</td><td>anayā / enāya</td><td></td></tr><tr><td>अनया / एनाय</td><td>ābhis</td><td></td><td></td></tr><tr><td>आभिस्</td><td></td><td></td><td></td></tr></tbody></table><p>Für den Gebrauch von enena etc. gilt das in <a href="./lektion07">Lektion 7</a> Gesagte.</p><p>Außer im Nominativ und Akkusativ sind die Formen der Neutra auf -a, des Fragepronomens und der Demonstrativpronomina mit den Formen des entsprechenden Maskulinums identisch.</p><h3 id="_10-2-1-zum-gebrauch-des-instrumentalis-trtiya-तृतीया" tabindex="-1">10.2.1. Zum Gebrauch des Instrumentalis (tṛtīyā = तृतीया) <a class="header-anchor" href="#_10-2-1-zum-gebrauch-des-instrumentalis-trtiya-तृतीया" aria-label="Permalink to &quot;10.2.1. Zum Gebrauch des Instrumentalis (tṛtīyā = तृतीया)&quot;">​</a></h3><p>Der Instrumentalis (tṛtīyā) steht hauptsächlich auf die Fragen:</p><ul><li>Wodurch?</li><li>Womit?</li><li>Mit wem?</li></ul><p>Er steht</p><ol><li>in Passivsätzen: Agens (kartṛ) im Instrumentalis</li><li>zur Angabe des Mittels oder Werkzeugs, mit dem etwas vollbracht wird</li><li>zur Angabe des Weges, auf dem jemand wohin gelangt</li><li>zum Ausdruck der Verbindung, Vereinigung, Begleitung von</li><li>bei Postpositionen in der Bedeutung &quot;zusammen mit, mit&quot;; z.B. saha = सह = &quot;mit&quot;<br> z.B.<br> brāhmaṇena saha = ब्राह्मणेन सह = &quot;gemeinsam mit dem Brahmanen&quot;</li></ol><p>Weitere Verwendungen des Instrumentalis (tṛtīyā) folgen später.</p><h2 id="_10-3-das-sogenannte-cerebralisationsgesetz-fur-n-ein-wortsandhi" tabindex="-1">10.3. Das sogenannte Cerebralisationsgesetz für -n- (ein Wortsandhi) <a class="header-anchor" href="#_10-3-das-sogenannte-cerebralisationsgesetz-fur-n-ein-wortsandhi" aria-label="Permalink to &quot;10.3. Das sogenannte Cerebralisationsgesetz für -n- (ein Wortsandhi)&quot;">​</a></h2><p>Ein -n-, auf das ein Vokal oder n, m, y, v folgt, wird durch -ṇ- ersetzt, wenn ṛ, ṝ, r, ṣ im Wort dem -n- vorausgehen oder kein anderer Laut als Vokale, Gutturale, Labiale, y, v, h oder Anusvāra zwischen diesen Lauten und dem folgenden -n- im Wort steht.</p><p>Deshalb:</p><table tabindex="0"><thead><tr><th></th><th>Instrumentalis singular</th></tr></thead><tbody><tr><td>guru</td><td></td></tr><tr><td>गुरु</td><td>guruṇā</td></tr><tr><td>गुरुणा</td><td></td></tr><tr><td>śūdra</td><td></td></tr><tr><td>शूद्र</td><td>śūdreṇa</td></tr><tr><td>शूद्रेण</td><td></td></tr><tr><td>īśvara</td><td></td></tr><tr><td>ईश्वर</td><td>īśvareṇa</td></tr><tr><td>ईश्वरेण</td><td></td></tr><tr><td>kṣatriya</td><td></td></tr><tr><td>क्षत्रिय</td><td>kṣatriyeṇa</td></tr><tr><td>क्षत्रियेण</td><td></td></tr><tr><td>naraka</td><td></td></tr><tr><td>नरक</td><td>narakeṇa</td></tr><tr><td>नरकेण</td><td></td></tr></tbody></table><p>So ist auch das -ṇ- zu erklären in:</p><blockquote><p>śravaṇa श्रवण</p><p>śṛṇoti शृणोति</p><p>kāraṇa कारण</p><p>brāhmaṇa ब्राह्मण</p></blockquote><h2 id="_10-4-das-passiv-indikativ-prasens-yak-यक्" tabindex="-1">10.4. Das Passiv, Indikativ Präsens (yak = यक्) <a class="header-anchor" href="#_10-4-das-passiv-indikativ-prasens-yak-यक्" aria-label="Permalink to &quot;10.4. Das Passiv, Indikativ Präsens (yak = यक्)&quot;">​</a></h2><p>Bildung:</p><p>(meist) tiefstufige Wurzel + -ya- + Ātmanepada-Endung</p><p>z.B.</p><table tabindex="0"><thead><tr><th>Wurzel</th><th>3.sg. Pass Präs. Indik.</th><th>3.pl.Pass.Präs.Indik.</th></tr></thead><tbody><tr><td>nī 1 U (nayati)</td><td></td><td></td></tr><tr><td>नी नयति</td><td>nī-ya-te</td><td></td></tr><tr><td>नीयते</td><td></td><td></td></tr><tr><td>&quot;er/sie/es wird geführt&quot;</td><td>nī-ya-nte</td><td></td></tr><tr><td>नीयन्ते</td><td></td><td></td></tr><tr><td>man 4 Ā (manyate)</td><td></td><td></td></tr><tr><td>मन् मन्यते</td><td>man-ya-te</td><td></td></tr><tr><td>मन्यते</td><td></td><td></td></tr><tr><td>&quot;er/sie/es wird gedacht&quot;</td><td>man-ya-nte</td><td></td></tr><tr><td>मन्यन्ते</td><td></td><td></td></tr><tr><td>viś 6 P (viśati)</td><td></td><td></td></tr><tr><td>विश् विशति</td><td>viś-ya-te</td><td></td></tr><tr><td>विश्यते</td><td></td><td></td></tr><tr><td>&quot;es wird eingetreten, es wird betreten&quot;</td><td>viś-ya-nte</td><td></td></tr><tr><td>विश्यन्ते</td><td></td><td></td></tr></tbody></table><p>Beachten Sie, dass bei Verben der 4. Präsensklasse das Ātmanepada und das Passiv identische Formen haben! Ob Ātmanepada oder Passiv vorliegt, lässt sich in diesem Fall nur aus der Satzkonstruktion erschließen.</p><h3 id="_10-4-1-sonderregeln-zur-bildung-des-passiv" tabindex="-1">10.4.1. Sonderregeln zur Bildung des Passiv <a class="header-anchor" href="#_10-4-1-sonderregeln-zur-bildung-des-passiv" aria-label="Permalink to &quot;10.4.1. Sonderregeln zur Bildung des Passiv&quot;">​</a></h3><p>1. Wurzeln, die auf -i oder -u auslauten, dehnen ihren Vokal vor dem Passivsuffix -ya-:</p><blockquote><p>z.B.<br> ji 1 P: jī-ya-te, jī-ya-nte जीयते ज्īयन्ते<br> śru 5 P: śrū-ya-te, śrū-ya-nte श्रूयते श्रूयन्ते<br> su 5 U: sū-ya-te, sū-ya-nte सूयते सूयन्ते</p></blockquote><p>2. Wurzeln mit -a- zwischen Konsonante, die weder nasale noch y, r, v sind, bleiben unverändert hochstufig:</p><blockquote><p>z.B.<br> labh 1 Ā: labh-ya-te, labh-ya-nte लभते लभ्यन्ते</p></blockquote><p>3. Auch folgende Wurzeln bilden ihr Passiv hochstufig bzw. in der Ablautstufe des Präsensstamms:</p><blockquote><p>āp 5 P: āp-ya-te, āp-ya-nte आप्यते आप्यन्ते<br> khād 1 P: khād-ya-te, khād-ya-nte खाद्यते खाद्यन्ते<br> smṛ 1 P: smar-ya-te, smar-ya-nte स्मर्यते स्मर्यन्ते</p></blockquote><p>4. Beachten Sie die Tiefstufe von Verben, die mit ya, va, ra beginnnen, bzw. bei denen diese Laute nach einem anderen Konsonanten stehen:</p><table tabindex="0"><thead><tr><th>Wurzel</th><th>Tiefstufe</th><th>Passiv</th></tr></thead><tbody><tr><td>yaj 1 U</td><td></td><td></td></tr><tr><td>यज्</td><td>*yj » ij</td><td>ij-ya-te</td></tr><tr><td>इज्यते</td><td></td><td></td></tr><tr><td>ij-ya-nte</td><td></td><td></td></tr><tr><td>इज्यन्ते</td><td></td><td></td></tr></tbody></table><p>| | vad 1 P<br> वद् | *vd » ud | ud-ya-te<br> उद्यते</p><p>ud-ya-nte<br> उद्यन्ते</p><p>| | prach 6 P<br> प्रछ् | *prcch » pṛcch | pṛcch-ya-te<br> पृच्छ्यते</p><p>pṛcch-ya-nte<br> पृच्छ्यन्ते</p><p>|</p><p>Die einheimische Bezeichnung für diese Bildung der Tiefstufe bei Verben mit ya bzw. va ist Samprasāraṇa n. = सम्प्रसारण.</p><p>5. Auslautendes -ṛ nach einem einzigen Konsonanten wird vor dem Passivsuffix -ya- durch -ri ersetzt:</p><blockquote><p>z.B.<br> kṛ 8 U: kri-ya-te, kri-ya-nte क्रियते क्रियन्ते</p><p>aber:<br> smṛ 1 P: smar-ya-te स्मर्यते</p></blockquote><p>6. Einige wurzeln auf -an haben alternativ zwei Passivstamm-Bildungen:</p><ul><li>eine -an-ya</li><li>eine -ā-ya- (das lange ā ist ein Vetreter für einen hypothetischen langen Nasal)</li></ul><blockquote><p>z.B.<br> tan 8 U.</p><ul><li>tan-ya-te, tan-ya-nte तन्यते तन्यन्ते</li><li>tā-ya-te, tā-ya-nte तायते तायन्ते (aus *tn-ya-nte)</li></ul></blockquote><h2 id="_10-5-wortliste" tabindex="-1">10.5. Wortliste <a class="header-anchor" href="#_10-5-wortliste" aria-label="Permalink to &quot;10.5. Wortliste&quot;">​</a></h2><p>Lernen Sie folgende Wörter:</p><p>gṛha n. गृह : Haus</p><p>grāma m. ग्राम : Dorf</p><p>nagara n. नगर : Stadt</p><p>(Zum Stadt- und Dorfleben siehe Basham, Wonder, Kap. 6)</p><p>yajña m. यज्ञ : Opfer (Das Opfer ist in Indien in erster Linie eine Verehrung der Gottheit als Gast. Dadurch verpflichtet man sich die Gottheit) (Wortbildung: yaj 1 U + kṛt-Suffix -na-)</p><p>puṇya n. पुण्य : gutes Werk, Verdienst (wodurch man sich Wohlergehen und gute Wiedergeburten verdient)</p><p>pāpa n. पाप : Übeltat, Böses (Gegensatz zu puṇya)</p><p>satya n. सत्य : Wahrheit (In Indien schrieb man dem wahren Wort Zauberkraft zu, ja die ganze Weltordnung wird durch das wahre Wort erhalten und Geschaffen. Zu dieser wichtigen Vorstellung siehe das grundlegende Werk:</p><blockquote><p>Lüders, Heinrich &lt;1869 - 1943&gt;: Varuna / Heinrich Lüders. Aus d. Nachl. hrsg. von Ludwig Alsdorf. - Göttingen : Vandenhoeck &amp; Ruprecht. -- Bd. 2: Varuna und das Ṛta. -- 1959. -- XXIII S., S. 340 - 764)</p></blockquote><p><img src="'+n+'" alt=""><br> Abb.: Gott Varuṇa = वरुण, 17. Jhdt.<br> [Bildquelle. Wikipedia, Public domain]</p><p>anṛta n. अनृत : Unwahrheit, Lüge (Gegensatz zu satya) (Wortbildung an- (&quot;un-&quot; + ṛta n., ṛta ist ein zentraler Begriff im Veda, dessen Übersetzung umstritten ist: &quot;Wahrheit&quot; (Lüders, Thieme), &quot;Ordnung&quot; (Renou))</p><p>ṛṣi m. ऋषि : vedischer Weiser, Verfasser vedischer Lieder (die Namen dieser ṛṣi&#39;s werden in den BRāhmaṇas sowie in eigenen Verzeichnissen zu den Veden genannt. Alle Brahmanen leiten ihre Herkunft von solchen ṛṣi&#39;s ab, nach denen ihre gotra गोत्र् benannt sind. Zum Begriff gotra siehe Basham, Wonder, Kap. 5)</p><p><img src="'+s+'" alt=""><br> Abb.: Ein Ṛṣi: Viśvāmitra (विश्वामित्र) / von Rāja Ravi Varmā (राज रवि वर्मा) &lt;1848 - 1906&gt;<br> [Bildquelle: Wikipedia, Public domain]</p><p>vad 1 P (vadati) वद् वदति : sagen, sprechen</p><p>prach 6 P (pṛcchati !) प्रछ् पृच्छति : fragen (jemanden;: Akk.; nach etwas: Akk.)</p><p>saha सह : zusammen mit, gemeinsam mit (auch bei kämpfen usw. mit): Postposition (wird nachgestellt) mit dem Instrumentalis.</p><h2 id="_10-6-ubung" tabindex="-1">10.6. Übung <a class="header-anchor" href="#_10-6-ubung" aria-label="Permalink to &quot;10.6. Übung&quot;">​</a></h2><p>A) Bilden Sie das Passiv zu folgenden Verbformen (mit Übersetzung der Verbform), d.h. das Passiv, das der Verbform in Person und Zahl entspricht:</p><ol><li>sṛjati सृजति</li><li>yudhyate युध्यते</li><li>bhavanti भवन्ति</li><li>yajati यजति</li><li>nṛtyati नृत्यति</li><li>nayanti नयन्ति</li><li>smarati स्मरति</li><li>śṛṇvanti शृण्वन्ति</li><li>pāśyati पश्यति (Passiv wird von dṛś gebildet!)</li><li>jayanti जयन्ति</li><li>kurvate कुर्वते</li><li>āpnuvanti आप्नुवन्ति</li><li>viśati विशति</li><li>khādanti खादन्ति</li><li>sunoti सुनोति</li><li>gacchati गच्छति</li><li>manyante मन्यन्ते</li><li>labhante लभन्ते</li><li>rakṣanti रक्षन्ति</li><li>vadanti वदन्ति</li><li>pṛcchanti पृच्छन्ति</li><li>tanvanti तन्वन्ति (2 Formen!)</li></ol><p>B) Bilden Sie den Instrumentalis singular und plural zu allen bisher gelernten Nomina</p><p>C) Setzen Sie folgende Sätze ins Passiv und übersetzen Sie sie:</p><p>1. brāhmaṇo devīm yajati. ब्राह्मणो देवीं यजति |</p><p>2. sādhuḥ svargaṃ gacchati. साधुः स्वर्गं गच्छति |</p><p>3. śūdraṃ jayati. शूद्रं जयति |</p><p>4. guruḥ phalāni khādati. गुरुः फलानि खादति |</p><p>5. gurūñchṛṇoti. गुरूञ्छृणोति |</p><p>6. ko &#39;gniṃ paśyati. को ऽग्निं पश्यति |</p><p>7. ayaṃ kavirmantraṃ smarati. अयं कविर्मन्त्रं स्मरति |</p><p>8. iyaṃ devī kṣatriyā rakṣati. इयं देवी क्त्रिया रक्षति |</p><p>9. kṣatriyā viṣṇuṃ yajante. क्षत्रिया विष्णुं यजन्ते | (2 Möglichkeiten)</p><p>10. brāhmaṇo &#39;gniṃ karoti. ब्राह्मणो ऽग्निं करोति |</p><p>11. vaiśyā imaṃ grāmaṃ gacchanti. वैश्या इमं ग्रामं गच्छन्ति | (2 Möglichkeiten)</p><p>12. ete gurūṃstu śṛṇvanti. एते गुरूंस्तु शृण्वन्ति |</p><p>13. sādhuḥ svargamāpnoti. साधुः स्वर्गमाप्नोति |</p><p>14. brāhmāṇāḥ somaṃ sunvanti. ब्राह्मणाः सोमं सुन्वन्ति |</p><p>15. paśūṃllabhate. पशूल्ंलभते |</p><p>16. ke yodhāḥ kṣatriyaiḥ saha yudhyante. के योधाः क्षत्रियैः सह युध्यन्ते |</p><p>D) Übersetzen Sie ins Sanskrit:</p><p>1. Ein Brahmane geht mit einem Vaiśya ins Dorf.</p><p>2. Er verehrt Viṣṇu mit einem Opfer. (Opfer yajña ausdrücken!)</p><p>3. Der Veda wird śruti genannt. (vad)</p><p>4. Man spannt die Webkette auf. (2 Möglichkeiten)</p><p><img src="'+u+'" alt=""><br> Abb.: Weberin, Bangladesh: die Webkette (Kettfäden sind die Längsfäden, durch die der Schuss gezogen wird)<br> [Bildquelle: USAID / Wikipedia, Public domain]</p><p>5. Lehrer fragen. (Passivkonstruktion)</p><p>6. Das Auge führt. (Passivkonstruktion) (Auge und Ohr werden sonst normalerweise im Dual verwendet)</p><p>7. Der Dichter sieht eine Gottheit. (Passivkonstruktion)</p><p>8. Wer (fem.) hütet das Mädchen? (Passivkonstruktion)</p><p>9. Der Kṣatriya verehr den HERRN mit einem Opfer. (Passivkonstruktion, ohne das Wort yajña zu verwenden)</p><p>10. Durch Freigebigkeit erreicht ein Anhänger des Buddha einen Himmel.</p><h2 id="_10-7-wortliste-2" tabindex="-1">10.7. Wortliste 2 <a class="header-anchor" href="#_10-7-wortliste-2" aria-label="Permalink to &quot;10.7. Wortliste 2&quot;">​</a></h2><p>Lernen Sie folgende Wörter:</p><p>makṣikā f. मक्षिका : Fliege, Biene</p><p>vraṇa m. व्रण : Wunde, Fehler, Schaden</p><p>dhana n. धन : Preis im Wettkampf; Lohn, Geld, Reichtum, Besitz</p><p>iṣ 6 P (icchati) (*iṣ-ccha-ti) इष् इच्छति : wünschen</p><p>pārthiva m. पार्थिव: Erdbeherrscher, König</p><p>nīca 3 नीच : niedrig tief</p><p>kalaha m. कलह : Streit, Zank</p><p>śānti f. शान्ति : Aufhören, Ruhe, Frieden</p><p>śam 4 P (śāmyati !) शम् शाम्यति : ruhig sein, ruhig werden</p><p>nara m. नर : Mann, Mensch</p><p>lubh 4 P (lubhyati) लुभ् लुभ्यति : begehren</p><p>sūkta 3 (= *su-ukta) सूक्त : gut gesagt, schön gesprochen; n. (vedisches) Lied</p><p>śiṣya m शिष्य : Schüler</p><p>atra अत्र : hier</p><p>tatra तत्र : dort</p><p>bhānu m. भानु : Glanz, Sonne</p><p>vand 1 Ā (vandate) वन्द् वन्दते : grüßen, ehren, verehren, preisen</p><p>vṛṣ 1 P (varṣati) वृष् वर्षति: regnen, beregnen (hat im Sanskrit einen kartṛ)</p><p>nṛpa m. नृप : Hüter der Männer: König, Fürst</p><p>kṣīra n. क्षीर : Milch</p><p>mārga m. मार्ग :  Wildwechsel: Weg</p><p>evam एवम् : so</p><p>iha इह : hier</p><p>śubh 1 Ā (śobhate) शुभ् शोभते : schön sein, glänzen</p><h2 id="_10-8-lese-und-ubersetzungsubung" tabindex="-1">10.8. Lese- und Übersetzungsübung <a class="header-anchor" href="#_10-8-lese-und-ubersetzungsubung" aria-label="Permalink to &quot;10.8. Lese- und Übersetzungsübung&quot;">​</a></h2><p>Lesen und übersetzen Sie und setzen Sie ins Passiv:</p><p>क</p><p>१.</p><blockquote><p>मक्षिका व्रणमिच्छन्ति<br> धनमिच्छन्ति पार्थिवाः |<br> नीचाः कलहमिच्छन्ति<br> शान्तिमिच्छन्ति साधवः ||</p></blockquote><p>२. नरान्सृजति देवः |</p><p>३. कवयो धनं लुभ्यन्ति |</p><p>४. ऋषिः सूक्तानि पश्यति |</p><p>५. विष्णुमृषिर्यजति |</p><p>६. गुरूञ्शिष्यांश्च पश्यति |</p><p>७. स्वर्गं लभन्ते |</p><p>८. अत्रर्षिर्भानुं वन्दते |</p><p>९. ग्रामं गच्छन्ति |</p><p>१०. दानानि वर्षन्ति नृपाः ||</p><p>ख</p><p>१. सदा देवान्स्मरन्ति |</p><p>२. ऋषिभी रामो वसति |</p><p>३. हरिं क्षीरेण यजति |</p><p>४. मार्गेण ग्रामं गच्छन्ति |</p><p>५. धनेन सुखमिच्छन्ति नराः |</p><p>६. एवं वदन्ति |</p><p>७. शान्त्यर्षय इह शोभन्ते |</p><p>८. कपयः फलानि खादन्ति |</p><p>९. गजो गच्छति |</p><p>१०. हरिर्गृहं गच्छति |</p><p>११. सारथी रथं नयति ||</p>',181)])])}const v=d(l,[["render",p]]);export{k as __pageData,v as default};
